<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Personal Expense Tracker</title>
  <style>
    body { font-family: sans-serif; margin: 20px; }
    #form-error { color: red; margin-top: 5px; }
    .expense { display: flex; justify-content: space-between; align-items: center; border-bottom: 1px solid #ccc; padding: 8px 0; }
    .exp-del { cursor: pointer; color: red; }
    table { width: 100%; margin-top: 20px; }
    th, td { text-align: left; padding: 5px; }
    #total { font-weight: bold; margin-top: 15px; }
    .cat-total { margin-top: 8px; }
  </style>
</head>
<body>
  <h1>Personal Expense Tracker</h1>

  <form id="expense-form">
    <label>Amount:
      <input type="number" id="amount" required />
    </label>
    <label>Category:
      <select id="category">
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>
    </label>
    <label>Date:
      <input type="date" id="date" required />
    </label>
    <label>Note:
      <input type="text" id="note" />
    </label>
    <button type="submit" id="add-expense">Add Expense</button>
    <div id="form-error"></div>
  </form>

  <div>
    <label>Filter by Category:
      <select id="filter-category">
        <option value="all">All</option>
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>
    </label>
    <label>From:
      <input type="date" id="filter-from" />
    </label>
    <label>To:
      <input type="date" id="filter-to" />
    </label>
  </div>

  <table id="expense-list">
    <thead>
      <tr>
        <th>Amount</th>
        <th>Category</th>
        <th>Date</th>
        <th>Note</th>
        <th>Action</th>
      </tr>
    </thead>
    <tbody></tbody>
  </table>

  <div id="total">Total: $0.00</div>
  <div id="category-summary"></div>

  <script>
    document.addEventListener('DOMContentLoaded', function () {
      let expenses = [];
      const saved = localStorage.getItem('expenses');
      if (saved) {
        try {
          expenses = JSON.parse(saved);
        } catch (e) {
          console.error("Failed to parse stored expenses", e);
        }
      }

      function saveExpenses() {
        localStorage.setItem('expenses', JSON.stringify(expenses));
      }

      document.getElementById('expense-form').addEventListener('submit', function (e) {
        e.preventDefault();
        const amountInput = document.getElementById('amount');
        const categoryEl = document.getElementById('category');
        const dateInput = document.getElementById('date');
        const noteInput = document.getElementById('note');

        const amount = parseFloat(amountInput.value);
        const category = categoryEl.value;
        const date = dateInput.value;
        const note = noteInput.value;

        let errorText = '';
        if (isNaN(amount) || amount <= 0) {
          errorText = 'Amount must be a positive number.';
        } else if (!date) {
          errorText = 'Date is required.';
        }

        const errorEl = document.getElementById('form-error');
        if (errorText) {
          errorEl.textContent = errorText;
          return;
        } else {
          errorEl.textContent = '';
        }

        expenses.unshift({ amount, category, date, note });
        saveExpenses();
        amountInput.value = '';
        noteInput.value = '';
        renderExpenses();
      });

      function renderExpenses() {
        const tbody = document.querySelector('#expense-list tbody');
        tbody.innerHTML = '';

        const categoryFilter = document.getElementById('filter-category').value;
        const from = document.getElementById('filter-from').value;
        const to = document.getElementById('filter-to').value;

        let filteredIndices = expenses.map((e, i) => {
          let matchesCategory = (categoryFilter === 'all') || (e.category === categoryFilter);
          let dateOk = true;
          if (from && to) {
            dateOk = new Date(e.date) >= new Date(from) && new Date(e.date) <= new Date(to);
          } else if (from) {
            dateOk = new Date(e.date) >= new Date(from);
          } else if (to) {
            dateOk = new Date(e.date) <= new Date(to);
          }
          return matchesCategory && dateOk ? i : null;
        }).filter(i => i !== null);

        filteredIndices.forEach(index => {
          const e = expenses[index];
          const tr = document.createElement('tr');
          tr.className = 'expense';
          tr.innerHTML = `
            <td>$${e.amount.toFixed(2)}</td>
            <td>${e.category}</td>
            <td>${e.date}</td>
            <td>${e.note || ''}</td>
            <td><span class="exp-del">Delete</span></td>
          `;
          tbody.appendChild(tr);
          tr.querySelector('.exp-del').addEventListener('click', () => {
            expenses.splice(index, 1);
            saveExpenses();
            renderExpenses();
          });
        });

        const total = filteredIndices.reduce((sum, i) => sum + expenses[i].amount, 0).toFixed(2);
        document.getElementById('total').textContent = `Total: $${total}`;

        updateCategoryTotals(filteredIndices);
      }

      function updateCategoryTotals(filteredIndices) {
        const categories = ['groceries', 'transport', 'bills', 'fun'];
        const summaryContainer = document.getElementById('category-summary');
        summaryContainer.innerHTML = '';
        const categorySums = {};
        for (const cat of categories) {
          categorySums[cat] = filteredIndices.reduce((sum, i) => {
            if (expenses[i].category === cat) return sum + expenses[i].amount;
            return sum;
          }, 0).toFixed(2);
        }

        for (const [cat, sum] of Object.entries(categorySums)) {
          const el = document.createElement('div');
          el.className = 'cat-total';
          el.setAttribute('data-cat', cat);
          let name;
          switch(cat) {
            case 'groceries': name = 'Groceries'; break;
            case 'transport': name = 'Transport'; break;
            case 'bills': name = 'Bills'; break;
            case 'fun': name = 'Fun'; break;
          }
          el.textContent = `${name}: $${sum}`;
          summaryContainer.appendChild(el);
        }
      }

      document.getElementById('filter-category').addEventListener('change', renderExpenses);
      document.getElementById('filter-from').addEventListener('change', renderExpenses);
      document.getElementById('filter-to').addEventListener('change', renderExpenses);

      renderExpenses();
    });
  </script>
</body>
</html>
